sequence.script:
var payload = mc.getPayloadJSON();

var result = {
    amount: (payload.amount != null) ? payload.amount * 100 : null,
    currency: payload.currency ? payload.currency : "USD",
    destination: payload.destination ? payload.destination : "btok_us_verified"
};

mc.setPayloadJSON(result);

var payload = mc.getPayloadJSON();
var inputData = mc.getProperty("inputData");

// If inputData is stored as String, parse it (safe guard)
if (typeof inputData === "string") {
    inputData = JSON.parse(inputData);
}

var result = {
    payoutId: payload.id,
    agentId: inputData ? inputData.agentId : null,
    amount: payload.amount / 100,
    currency: payload.currency,
    arrivalDate: payload.arrival_date ? new Date(payload.arrival_date).toISOString() : null,
    balanceTransactionId: payload.balance_transaction,
    created: payload.created ? new Date(payload.created).toISOString() : null,
    destinationId: payload.destination,
    method: payload.method,
    sourceType: payload.source_type,
    status: payload.status
};

// Conditional fields from inputData
if (inputData) {
    if (inputData.policyNumber !== null && inputData.policyNumber !== undefined) {
        result.policyNumber = inputData.policyNumber;
    }
    if (inputData.quoteId !== null && inputData.quoteId !== undefined) {
        result.quoteId = inputData.quoteId;
    }
    if (inputData.partyIdentifier !== null && inputData.partyIdentifier !== undefined) {
        result.partyIdentifier = inputData.partyIdentifier;
    }
}

mc.setPayloadJSON(result);
